587: test "expect State.add handles non-Telex characters less than buffer_effective range" {
588:     // Arrange
589:     var state: State = undefined;
590:     state.init();
591:     state.mode = .telex;
592: 
593:     const input_sequence = "bbbbbqqqqq";
594: 
